import requests

def test_get_stream_with_invalid_video_url():
    base_url = "http://localhost:3000"
    invalid_url = "invalid-url"

    try:
        response = requests.get(f"{base_url}/api/stream", params={"url": invalid_url}, timeout=30)
    except requests.RequestException as e:
        assert False, f"Request failed with exception: {e}"
    else:
        assert response.status_code == 502, f"Expected status code 502, got {response.status_code}"

test_get_stream_with_invalid_video_url()

import requests

def test_get_proxy_without_endpoint_parameter():
    base_url = "http://localhost:3000/api/proxy"
    headers = {
        "Accept": "*/*"
    }
    try:
        response = requests.get(base_url, headers=headers, timeout=30)
        assert response.status_code == 400, f"Expected status code 400, got {response.status_code}"
        # The response content could be error message or fallback image, ensure not empty
        assert response.content, "Response content is empty"
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

test_get_proxy_without_endpoint_parameter()

import requests

def test_get_proxy_with_invalid_image_endpoint():
    base_url = "http://localhost:3000"
    endpoint_url = "/api/proxy"
    invalid_image_url = "http://invalid-url-for-testing-image-proxy"

    params = {"endpoint": invalid_image_url}
    try:
        response = requests.get(base_url + endpoint_url, params=params, timeout=30)
        assert response.status_code == 500, f"Expected status code 500, got {response.status_code}"
    except requests.RequestException as e:
        assert False, f"Request failed with an exception: {e}"

test_get_proxy_with_invalid_image_endpoint()
